export default function FormSubmitted({ formTitle = "Ответ на приглашение" }) {
  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@300;400;500;600&family=DM+Serif+Display&display=swap');
        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
        body { font-family: 'DM Sans', sans-serif; background: #f0f0f0; }

        .page {
          min-height: 100vh;
          background: #f0f0f0;
          display: flex;
          flex-direction: column;
        }

        .topbar {
          background: #1f1f1f;
          color: #9ca3af;
          font-size: 12px;
          padding: 7px 14px;
        }

        .content {
          flex: 1;
          display: flex;
          flex-direction: column;
          align-items: center;
          padding: 0 16px 60px;
        }

        .hero-placeholder {
          width: 100%;
          max-width: 480px;
          height: 180px;
          background: linear-gradient(135deg, #4b5563 0%, #374151 50%, #1f2937 100%);
          border-radius: 0 0 4px 4px;
          display: flex;
          align-items: center;
          justify-content: center;
          color: #9ca3af;
          font-size: 14px;
        }

        .card {
          width: 100%;
          max-width: 480px;
          background: #fff;
          border-radius: 4px;
          padding: 40px 32px;
          text-align: center;
          margin-top: 32px;
          box-shadow: 0 2px 8px rgba(0,0,0,0.1);
        }

        .checkmark {
          width: 60px;
          height: 60px;
          background: #10b981;
          border-radius: 50%;
          display: flex;
          align-items: center;
          justify-content: center;
          font-size: 32px;
          margin: 0 auto 20px;
        }

        h1 {
          font-size: 20px;
          font-weight: 600;
          color: #1f2937;
          margin-bottom: 8px;
        }

        p {
          font-size: 14px;
          color: #6b7280;
          margin-bottom: 24px;
          line-height: 1.6;
        }

        .button {
          background: #4f46e5;
          color: #fff;
          border: none;
          padding: 10px 24px;
          border-radius: 6px;
          font-size: 14px;
          font-weight: 600;
          cursor: pointer;
          font-family: 'DM Sans', sans-serif;
          transition: background 0.2s;
        }

        .button:hover {
          background: #4338ca;
        }

        .button.secondary {
          background: transparent;
          color: #4f46e5;
          border: 1px solid #4f46e5;
          margin-left: 12px;
        }

        .button.secondary:hover {
          background: #f5f3ff;
        }

        .actions {
          display: flex;
          gap: 12px;
          justify-content: center;
          margin-top: 20px;
        }

        .footer {
          margin-top: 32px;
          padding-top: 24px;
          border-top: 1px solid #e5e7eb;
          font-size: 12px;
          color: #9ca3af;
        }
      `}</style>

      <div className="page">
        <div className="topbar">
          forms.google.com
        </div>

        <div className="content">
          <div className="hero-placeholder">
            Изображение формы
          </div>

          <div className="card">
            <div className="checkmark">✓</div>
            <h1>Спасибо за ответ</h1>
            <p>Ваш ответ на форму "{formTitle}" был успешно отправлен.</p>

            <div className="actions">
              <button className="button" onClick={() => window.location.href = "/"}>
                Вернуться на главную
              </button>
              <button className="button secondary" onClick={() => window.location.reload()}>
                Создать новый ответ
              </button>
            </div>

            <div className="footer">
              Этот контент источник не принадлежит Google.
            </div>
          </div>
        </div>
      </div>
    </>
  );
}
